var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"GRANDFA_NPC_SUMMER_NULL","text":{"KOREA":"그러니까 이…… 넷튜브인지로 우리 마을 사정이 알려졌다고?","JPN":"つまりこの……ネットチューブなんちゃらでうちの村の事情が広まったと？","ENG":"So... now people know what’s going on in our town, thanks to the NetTube thing?","TWN":"所以你是說……現在大家都在這個大平台上，看到我們村裡的情況了？"},"stage":{"bg":"VILLAGE2","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GRANDMA_NPC_SUMMER_NULL","text":{"KOREA":"아이고, 그럼 여기 있는 숫자가 다 우리 마을 얘기를 아는 사람들인가?","JPN":"おお、じゃあここの数字が全部うちの村の話を知っている人たちかね？","ENG":"This is the number of people who know about us?","TWN":"哎呀，那這裡的數字，是知道我們村裡情況的人數嗎？"},"stage":{"bg":"VILLAGE2","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"헤헷, 그렇슴다! 이제 구경하러 오는 사람들이 무지 많을 검다!","JPN":"へへっ、そうっすね！　これで村に来る人が増えると思うっす！","ENG":"Yes, ma’am! Now everyone will come and visit our town!","TWN":"嘿嘿，對的唷！之後會有超多人來這裡觀光喔！"},"stage":{"bg":"VILLAGE2","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GRANDFA_NPC_SUMMER_NULL","text":{"KOREA":"허허, 모네도 그렇고 그 작은 애들도 그렇고 우리 마을 복덩이야.","JPN":"ははは、モネもそうじゃし、あのちびっ子たちも我が村の宝物じゃ。","ENG":"Hah hah, all these Mones, big and small, are blessings to our town.","TWN":"呵呵，莫妮和那些小朋友都是我們村子的福星呢！"},"stage":{"bg":"VILLAGE2","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GRANDMA_NPC_SUMMER_NULL","text":{"KOREA":"그래요. 도시 사는 손녀들이 놀러 온 것 같아서 보기도 좋네.","JPN":"そうじゃな。都会に住む孫娘たちが遊びに来たみたいで嬉しいのう。","ENG":"Yes, and seeing them reminds me of my grandchildren.","TWN":"就是說啊，感覺就像是住在城市的孫女回來玩一樣，看了就開心。"},"stage":{"bg":"VILLAGE2","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"고객님!","JPN":"お客様！","ENG":"Excuse me!","TWN":"客人！"},"stage":{"bg":"VILLAGE2","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"음? 예거 양? 그렇게 급하게 어딜 가는 건가?","JPN":"うん？　イェーガーさん？　そんなに急いでどこに行くんだ？","ENG":"Hm? Ms. Jaegar? Where are you hurrying to?","TWN":"嗯？伊格？你急著要去哪裡？"},"stage":{"bg":"VILLAGE2","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"앗, 네. 물류센터에서 지원 요청이 들어와서 급히 가 봐야 할 거 같아요.","JPN":"あっ、はい。物流センターから支援要請が届いたので急いで行かなければなりません。","ENG":"Oh, I had an urgent call, I have to go help the Distribution Center.","TWN":"那個，因為物流中心請求支援，我要趕過去一趟。"},"stage":{"bg":"VILLAGE2","slots":{"L":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L16_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"배달 일이라면 여기 머무는 동안 자주 다녀오지 않았나?","JPN":"配達の仕事なら、ここに滞在している間も何回か行ってきたのではないか？","ENG":"But you’ve been taking care of delivery tasks while you were staying here.","TWN":"是要送貨嗎？你在這裡的這段時間，不是一直在送貨嗎？"},"stage":{"bg":"VILLAGE2","slots":{"L":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"이번에는 좀 오래 걸릴 것 같아서요.","JPN":"今回はちょっと長くかかりそうです。","ENG":"This new job will take longer than that.","TWN":"這次可能會需要比較長的時間。"},"stage":{"bg":"VILLAGE2","slots":{"L":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"샤레이드에서 일어난 이상 기후 때문에 수송기 몇 대가 불시착했다나 봐요.","JPN":"シャレードで起きた異常気象のせいで、輸送機が数機不時着したらしいです。","ENG":"A number of Transport Craft crashed because of the weather anomaly in Charade.","TWN":"在查雷德發生的氣候異常，好像導致幾架運輸機臨時迫降的樣子。"},"stage":{"bg":"VILLAGE2","slots":{"L":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"이상 기후라면…… 대균열 때문에?","JPN":"異常気象ってことは……大亀裂のせいか？","ENG":"The weather anomaly... because of the Grand Dimension Crevice?","TWN":"氣候異常… 因為大峽谷嗎？"},"stage":{"bg":"VILLAGE2","slots":{"L":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"하지만 얼마 전에 기상 조절기들이 배치됐을 텐데?","JPN":"しかし、この前気象調節機が配置されたはずだが？","ENG":"But they recently installed a Weather Controller, didn’t they?","TWN":"不過不是之前才配置氣象調節器的嗎？"},"stage":{"bg":"VILLAGE2","slots":{"L":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"으음, 거기까지는 저도 잘 모르겠네요.","JPN":"うーん、そこまでは私もよく分かりません。","ENG":"I don’t know.","TWN":"嗯，詳細情形我也不太清楚。"},"stage":{"bg":"VILLAGE2","slots":{"L":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"아마 현지에 가면 더 자세히 알 수 있지 않을까요?","JPN":"おそらく現地に行けばもっと詳しい事情が分かるでしょう。","ENG":"Maybe I’ll find out when I actually get there.","TWN":"直接去現場看比較快。"},"stage":{"bg":"VILLAGE2","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"그러면 저는 이만! 주문하실 거 있으면 바로 연락 주세요!","JPN":"それでは私はこれで失礼します！　注文したいものがあればいつでも連絡ください！","ENG":"I’m going now! Please call me when you have a request!","TWN":"那我先走囉！有需要服務的地方再找我喔！"},"stage":{"bg":"VILLAGE2","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"오, 그래. 잘 가게나. 덕분에 좋은 휴양지를 찾았어.","JPN":"ああ、そうだな。いってらっしゃい。おかげで良いリゾート地に来れて助かった。","ENG":"Oh, okay. Goodbye then, and thank you for finding us this wonderful place.","TWN":"好喔，慢走～謝謝你幫我們找到這麼棒的地方度假。"},"stage":{"bg":"VILLAGE2","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};